# List all user flows (authentication events flows) in the External ID tenant
Connect-MgGraph -TenantId 'your-ciam-tenant.onmicrosoft.com' \
    -Scopes 'EventListener.Read.All'

$flows = Invoke-MgGraphRequest -Method GET \
    -Uri 'https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows'
$flows.value | ForEach-Object {
    [pscustomobject]@{
        DisplayName = $_.displayName
        Id          = $_.id
        Priority    = $_.priority
        OdataType   = $_.'@odata.type'
    }
} | Format-Table

# Create a sign-up/sign-in user flow with email+password and Google
$flowBody = @{
    '@odata.type'  = '#microsoft.graph.externalUsersSelfServiceSignUpEventsFlow'
    displayName    = 'CustomerSignUpSignIn'
    priority       = 500
    conditions     = @{
        applications = @{
            includeAllApplications = $false
            includeApplications    = @( @{ appId = 'your-app-client-id' } )
        }
    }
    onInteractiveAuthFlowStart = @{
        '@odata.type'   = '#microsoft.graph.graphOnInteractiveAuthFlowReadyHandler'
        isSignUpAllowed = $true
    }
    onAuthenticationMethodLoadStart = @{
        '@odata.type'       = '#microsoft.graph.graphOnAuthenticationMethodLoadStartHandler'
        identityProviders   = @(
            @{ id = 'EmailPassword-OAUTH2-v2' }
            @{ id = 'Google-OAUTH2-v2' }
        )
    }
    onAttributeCollection = @{
        '@odata.type' = '#microsoft.graph.graphOnAttributeCollectionHandler'
        attributes    = @(
            @{ id = 'email';       isOptional = $false; requiresVerification = $true }
            @{ id = 'displayName'; isOptional = $false; requiresVerification = $false }
            @{ id = 'country';     isOptional = $true;  requiresVerification = $false }
        )
    }
    onUserCreateStart = @{
        '@odata.type'    = '#microsoft.graph.graphOnUserCreateStartHandler'
        userTypeToCreate = 'member'
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows' \
    -Body $flowBody -ContentType 'application/json'

# Azure Function: API connector for onAttributeCollectionSubmit
# Validates email domain and enriches with subscription tier from CRM
import azure.functions as func
import json

def main(req: func.HttpRequest) -> func.HttpResponse:
    body = req.get_json()
    email = body.get('email', '')
    domain = email.split('@')[-1].lower() if '@' in email else ''

    # Block sign-ups from disposable email domains
    blocked_domains = ['mailinator.com', 'tempmail.com', 'guerrillamail.com']
    if domain in blocked_domains:
        return func.HttpResponse(
            json.dumps({
                'version': '1.0.0',
                'action': 'ShowBlockPage',
                'userMessage': 'Sign-ups from disposable email addresses are not allowed.'
            }),
            mimetype='application/json'
        )

    # Enrich with subscription tier from CRM lookup (simulated)
    tier = lookup_crm_tier(email)  # returns 'bronze', 'silver', 'gold'

    return func.HttpResponse(
        json.dumps({
            'version': '1.0.0',
            'action': 'Continue',
            'extension_<appId>_LoyaltyTier': tier
        }),
        mimetype='application/json'
    )

