# Link an API connector to the onAttributeCollectionSubmit event in a flow
$flowId      = "aaaabbbb-flow-id-1234"
$connectorId = "ccccdddd-conn-id-5678"

$patchBody = @{
    onAttributeCollectionSubmit = @{
        '@odata.type' = '#microsoft.graph.graphOnAttributeCollectionSubmitHandler'
        apiConnector  = @{
            '@odata.type'    = '#microsoft.graph.identityApiConnector'
            id               = $connectorId
        }
    }
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows/$flowId" \
    -Body $patchBody -ContentType 'application/json'
Write-Host 'API connector linked to onAttributeCollectionSubmit event'

# Set company branding for the External ID tenant sign-in pages
# Applies to all user flows in the tenant
$brandBody = @{
    signInPageText = 'Welcome to Contoso Customer Portal'
    usernameHintText = 'Enter your email address'
    backgroundImage = @{
        # base64-encoded PNG, max 1920x1080, max 300KB
        # You can set this via portal; Graph requires multipart/form-data
    }
    bannerLogo = @{
        # base64-encoded PNG/SVG, max 280x60px
    }
    squareLogo = @{
        # 240x240px, used on mobile / favicon contexts
    }
} | ConvertTo-Json -Depth 3

# Set default branding
Invoke-MgGraphRequest -Method PUT \
    -Uri 'https://graph.microsoft.com/v1.0/organization/<orgId>/branding' \
    -Body $brandBody -ContentType 'application/json'

# For per-locale overrides (e.g., French branding):
Invoke-MgGraphRequest -Method PUT \
    -Uri 'https://graph.microsoft.com/v1.0/organization/<orgId>/branding/localizations/fr-FR' \
    -Body (@{ signInPageText = 'Bienvenue sur le portail client Contoso' } | ConvertTo-Json) \
    -ContentType 'application/json'

# Bind a single user flow to multiple apps
# Useful when multiple apps share the same sign-up experience
$flowId = "aaaabbbb-flow-id-1234"

# PATCH the flow to add a second app to the conditions
$patchBody = @{
    conditions = @{
        applications = @{
            includeAllApplications = $false
            includeApplications = @(
                @{ appId = 'first-app-client-id' }
                @{ appId = 'second-app-client-id' }
                @{ appId = 'mobile-app-client-id' }
            )
        }
    }
} | ConvertTo-Json -Depth 6

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows/$flowId" \
    -Body $patchBody -ContentType 'application/json'
Write-Host 'User flow now bound to 3 apps'

# Create a profile editing flow (lets signed-in customers update their attributes)
$editFlowBody = @{
    '@odata.type'  = '#microsoft.graph.externalUsersSelfServiceSignUpEventsFlow'
    displayName    = 'CustomerProfileEdit'
    priority       = 400
    conditions     = @{
        applications = @{
            includeApplications = @( @{ appId = 'your-app-client-id' } )
        }
    }
    onInteractiveAuthFlowStart = @{
        '@odata.type'   = '#microsoft.graph.graphOnInteractiveAuthFlowReadyHandler'
        isSignUpAllowed = $false   # This is an EDIT flow, not sign-up
    }
    onAuthenticationMethodLoadStart = @{
        '@odata.type'     = '#microsoft.graph.graphOnAuthenticationMethodLoadStartHandler'
        identityProviders = @( @{ id = 'EmailPassword-OAUTH2-v2' } )
    }
    onAttributeCollection = @{
        '@odata.type' = '#microsoft.graph.graphOnAttributeCollectionHandler'
        attributes    = @(
            @{ id = 'givenName';    isOptional = $true; requiresVerification = $false }
            @{ id = 'surname';      isOptional = $true; requiresVerification = $false }
            @{ id = 'country';      isOptional = $true; requiresVerification = $false }
            @{ id = 'mobilePhone';  isOptional = $true; requiresVerification = $false }
        )
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows' \
    -Body $editFlowBody -ContentType 'application/json'

# Terraform (AzureAD provider preview): External ID user flow
# The azuread provider does not yet expose authenticationEventsFlows natively;
# use a null_resource with az rest to manage via ARM/Graph API from Terraform
resource "null_resource" "ciam_user_flow" {
  triggers = {
    flow_config = sha256(jsonencode({
      displayName = "CustomerSignUpSignIn"
      priority    = 500
    }))
  }

  provisioner "local-exec" {
    command = <<-EOT
      az rest --method post \
        --url https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows \
        --headers 'Content-Type=application/json' \
        --body '@flow-config.json'
    EOT
  }
}

# flow-config.json contains the full flow body from the PowerShell example above
# Alternative: manage user flows via Azure Portal for simpler day-to-day operations
